export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(toKey));
  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(toKey([x + dx, y + dy]))).length;

  const survives = (cell: Cell): boolean => {
    const neighborCount = countLiveNeighbors(cell);
    return neighborCount === 2 || neighborCount === 3;
  };

  const survivors = liveCells.filter(survives);

  const deadCandidateKeys = new Set<string>();
  const deadCandidates: Cell[] = [];
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = toKey(neighbor);
      if (liveSet.has(k)) continue;
      if (deadCandidateKeys.has(k)) continue;
      deadCandidateKeys.add(k);
      deadCandidates.push(neighbor);
    }
  }
  const born = deadCandidates.filter((cell) => countLiveNeighbors(cell) === 3);

  return [...survivors, ...born];
}

