export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(toKey));
  const isAlive = (cell: Cell): boolean => liveSet.has(toKey(cell));

  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(isAlive).length;

  const livesNextGeneration = (cell: Cell): boolean => {
    const liveNeighbors = countLiveNeighbors(cell);
    return isAlive(cell) ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
  };

  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    candidates.set(toKey(cell), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(toKey(neighbor), neighbor);
    }
  }

  return [...candidates.values()].filter(livesNextGeneration);
}

